	   snap in/out with no fade — the typewriter character lives in the hard
	   on/off; any motion comes from animating the progress prop, not from CSS. */
	.wordmark-svg path {
		fill: currentColor;
		opacity: 0;
	}

	.wordmark-svg path.lit {
		opacity: 1;
	}
</style>
